"use client";

import { useEffect, useMemo, useState } from "react";

type Row = {
  no: number;
  esl: string;
  jabatan: string;
  namaPktGolNrpNip: string;
  kondisi: string;
  calonPengisiJabatan: string;
  catatan: string;
  ket: string;
};

const STORAGE_KEY = "bnn_bahan_rapat_rows_v1";

function createEmptyRow(no: number): Row {
  return {
    no,
    esl: "",
    jabatan: "",
    namaPktGolNrpNip: "",
    kondisi: "",
    calonPengisiJabatan: "",
    catatan: "",
    ket: "",
  };
}

function toCSV(rows: Row[]) {
  const header = [
    "NO",
    "ESL",
    "JABATAN",
    "NAMA/PKT/GOL NRP/NIP",
    "KONDISI",
    "CALON PENGISI JABATAN",
    "CATATAN",
    "KET",
  ];

  const escape = (v: string | number) => {
    const s = String(v ?? "");
    // escape double quotes, wrap with quotes
    return `"${s.replace(/"/g, '""')}"`;
  };

  const lines = [
    header.map(escape).join(","),
    ...rows.map((r) =>
      [
        r.no,
        r.esl,
        r.jabatan,
        r.namaPktGolNrpNip,
        r.kondisi,
        r.calonPengisiJabatan,
        r.catatan,
        r.ket,
      ]
        .map(escape)
        .join(",")
    ),
  ];

  return lines.join("\n");
}

export default function BahanRapatPage() {
  const [rows, setRows] = useState<Row[]>([
    createEmptyRow(1),
    createEmptyRow(2),
    createEmptyRow(3),
  ]);
  const [savedAt, setSavedAt] = useState<string>("");

  // load from localStorage
  useEffect(() => {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return;
      const parsed = JSON.parse(raw) as Row[];
      if (Array.isArray(parsed) && parsed.length > 0) setRows(parsed);
    } catch {}
  }, []);

  // autosave
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(rows));
      setSavedAt(new Date().toLocaleString());
    } catch {}
  }, [rows]);

  const totalRows = useMemo(() => rows.length, [rows]);

  const updateCell = (index: number, key: keyof Row, value: string) => {
    setRows((prev) => {
      const next = [...prev];
      next[index] = { ...next[index], [key]: value };
      return next;
    });
  };

  const addRow = () => {
    setRows((prev) => [...prev, createEmptyRow(prev.length + 1)]);
  };

  const deleteRow = (index: number) => {
    setRows((prev) => {
      const next = prev.filter((_, i) => i !== index);
      // re-number NO biar rapih
      return next.map((r, i) => ({ ...r, no: i + 1 }));
    });
  };

  const clearAll = () => {
    const ok = confirm("Reset semua data tabel?");
    if (!ok) return;
    setRows([createEmptyRow(1), createEmptyRow(2), createEmptyRow(3)]);
  };

  const manualSave = () => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(rows));
      alert("Data tersimpan (LocalStorage).");
    } catch {
      alert("Gagal menyimpan.");
    }
  };

  const exportCSV = () => {
    const csv = toCSV(rows);
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);

    const a = document.createElement("a");
    a.href = url;
    a.download = `bahan_rapat_${Date.now()}.csv`;
    document.body.appendChild(a);
    a.click();
    a.remove();

    URL.revokeObjectURL(url);
  };

  return (
    <div className="min-h-screen bg-zinc-50">
      {/* wrapper mengikuti style kamu: bubble background bisa tetap dari layout dashboard */}
      <div className="mx-auto max-w-6xl px-5 py-6 md:px-8">
        {/* Card besar seperti gambar */}
        <div className="rounded-2xl bg-white shadow-xl ring-1 ring-black/5">
          {/* Header dokumen */}
          <div className="px-10 pt-10">
            <div className="flex items-start justify-between gap-6">
              <div className="text-[12px] font-semibold leading-5 text-zinc-900">
                BADAN NARKOTIKA NASIONAL <br />
                REPUBLIK INDONESIA
                <div className="mt-3 h-[2px] w-[320px] bg-zinc-700/60" />
              </div>

              <div className="text-center">
                <div className="text-[12px] font-semibold text-zinc-900">
                  MATERI RAPAT
                </div>
                <div className="mt-1 text-[12px] text-zinc-600">
                  Tanggal XX XXX 2025
                </div>
              </div>

              <div className="w-[320px]" />
            </div>

            {/* Toolbar */}
            <div className="mt-8 flex flex-wrap items-center justify-between gap-3">
              <div className="text-xs text-zinc-500">
                {totalRows} baris • Auto-save:{" "}
                <span className="font-medium text-zinc-700">{savedAt}</span>
              </div>

              <div className="flex flex-wrap gap-2">
                <button
                  onClick={addRow}
                  className="rounded-lg bg-[#123473] px-3 py-2 text-xs font-semibold text-white hover:bg-[#0f2e5f]"
                >
                  + Tambah Baris
                </button>
                <button
                  onClick={manualSave}
                  className="rounded-lg border border-zinc-200 bg-white px-3 py-2 text-xs font-semibold text-zinc-800 hover:bg-zinc-50"
                >
                  Simpan
                </button>
                <button
                  onClick={exportCSV}
                  className="rounded-lg border border-zinc-200 bg-white px-3 py-2 text-xs font-semibold text-zinc-800 hover:bg-zinc-50"
                >
                  Export CSV (Excel)
                </button>
                <button
                  onClick={clearAll}
                  className="rounded-lg border border-red-200 bg-white px-3 py-2 text-xs font-semibold text-red-700 hover:bg-red-50"
                >
                  Reset
                </button>
              </div>
            </div>
          </div>

          {/* Table */}
          <div className="px-10 pb-10 pt-6">
            <div className="overflow-x-auto rounded-xl border border-zinc-200">
              <table className="w-full min-w-[1100px] border-collapse">
                <thead className="bg-zinc-50">
                  <tr className="text-left text-[11px] font-semibold text-zinc-700">
                    <th className="w-[70px] border-b border-zinc-200 px-4 py-3">
                      NO
                    </th>
                    <th className="w-[110px] border-b border-zinc-200 px-4 py-3">
                      ESL
                    </th>
                    <th className="w-[240px] border-b border-zinc-200 px-4 py-3">
                      JABATAN
                    </th>
                    <th className="w-[240px] border-b border-zinc-200 px-4 py-3">
                      NAMA/PKT/GOL <br /> NRP/NIP
                    </th>
                    <th className="w-[150px] border-b border-zinc-200 px-4 py-3">
                      KONDISI
                    </th>
                    <th className="w-[240px] border-b border-zinc-200 px-4 py-3">
                      CALON PENGISI <br /> JABATAN
                    </th>
                    <th className="w-[180px] border-b border-zinc-200 px-4 py-3">
                      CATATAN
                    </th>
                    <th className="w-[120px] border-b border-zinc-200 px-4 py-3">
                      KET
                    </th>
                    <th className="w-[70px] border-b border-zinc-200 px-4 py-3 text-center">
                      {" "}
                    </th>
                  </tr>
                </thead>

                <tbody>
                  {rows.map((r, idx) => (
                    <tr key={idx} className="text-[12px] text-zinc-800">
                      <td className="border-b border-zinc-200 px-4 py-2 align-top">
                        {r.no}
                      </td>

                      <td className="border-b border-zinc-200 px-3 py-2">
                        <input
                          value={r.esl}
                          onChange={(e) => updateCell(idx, "esl", e.target.value)}
                          className="w-full rounded-md bg-transparent px-1 py-1 outline-none focus:bg-[#123473]/5"
                        />
                      </td>

                      <td className="border-b border-zinc-200 px-3 py-2">
                        <input
                          value={r.jabatan}
                          onChange={(e) =>
                            updateCell(idx, "jabatan", e.target.value)
                          }
                          className="w-full rounded-md bg-transparent px-1 py-1 outline-none focus:bg-[#123473]/5"
                        />
                      </td>

                      <td className="border-b border-zinc-200 px-3 py-2">
                        <input
                          value={r.namaPktGolNrpNip}
                          onChange={(e) =>
                            updateCell(idx, "namaPktGolNrpNip", e.target.value)
                          }
                          className="w-full rounded-md bg-transparent px-1 py-1 outline-none focus:bg-[#123473]/5"
                        />
                      </td>

                      <td className="border-b border-zinc-200 px-3 py-2">
                        <input
                          value={r.kondisi}
                          onChange={(e) =>
                            updateCell(idx, "kondisi", e.target.value)
                          }
                          className="w-full rounded-md bg-transparent px-1 py-1 outline-none focus:bg-[#123473]/5"
                        />
                      </td>

                      <td className="border-b border-zinc-200 px-3 py-2">
                        <input
                          value={r.calonPengisiJabatan}
                          onChange={(e) =>
                            updateCell(
                              idx,
                              "calonPengisiJabatan",
                              e.target.value
                            )
                          }
                          className="w-full rounded-md bg-transparent px-1 py-1 outline-none focus:bg-[#123473]/5"
                        />
                      </td>

                      <td className="border-b border-zinc-200 px-3 py-2">
                        <input
                          value={r.catatan}
                          onChange={(e) =>
                            updateCell(idx, "catatan", e.target.value)
                          }
                          className="w-full rounded-md bg-transparent px-1 py-1 outline-none focus:bg-[#123473]/5"
                        />
                      </td>

                      <td className="border-b border-zinc-200 px-3 py-2">
                        <input
                          value={r.ket}
                          onChange={(e) => updateCell(idx, "ket", e.target.value)}
                          className="w-full rounded-md bg-transparent px-1 py-1 outline-none focus:bg-[#123473]/5"
                        />
                      </td>

                      <td className="border-b border-zinc-200 px-2 py-2 text-center">
                        <button
                          onClick={() => deleteRow(idx)}
                          className="rounded-md px-2 py-1 text-[11px] font-semibold text-red-700 hover:bg-red-50"
                          title="Hapus baris"
                        >
                          Hapus
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Footer doc */}
            <div className="mt-10 text-[12px] text-zinc-700">
              Biro SDM Aparatur dan Organisasi <br />
              Sekretariat Utama BNN 2025
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
